import{_ as a,c as i,m as e,a as o,t as r,U as n,o as s}from"./chunks/framework.9QHaLlVJ.js";const f=JSON.parse('{"title":"初始化容器详解","description":"","frontmatter":{"title":"初始化容器详解"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Pod/初始化容器/初始化容器.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Pod/初始化容器/初始化容器.md","lastUpdated":1705214817000}'),l={name:"doc/DevOps/Kubernetes/基础/Pod/初始化容器/初始化容器.md"},d={id:"frontmatter-title",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=n('<p>Init 容器与普通的容器非常像，除了如下两点：</p><ul><li>Init 容器总是运行到成功完成为止。</li><li>每个 Init 容器都必须在下一个 Init 容器启动之前成功完成。</li></ul><h3 id="与普通容器的不同之处" tabindex="-1">与普通容器的不同之处 <a class="header-anchor" href="#与普通容器的不同之处" aria-label="Permalink to &quot;与普通容器的不同之处&quot;">​</a></h3><p>Init 容器支持应用容器的全部字段和特性，包括资源限制、数据卷和安全设置。 然而，Init 容器对资源请求和限制的处理稍有不同，在下面 <a href="https://kubernetes.io/docs/concepts/workloads/pods/init-containers/#resources" target="_blank" rel="noreferrer">资源</a> 处有说明。 而且 Init 容器不支持 Readiness Probe，因为它们必须在 Pod 就绪之前运行完成。</p><p>如果为一个 Pod 指定了多个 Init 容器，那些容器会按顺序一次运行一个。只有当前面的 Init 容器必须运行成功后，才可以运行下一个 Init 容器。当所有的 Init 容器运行完成后，Kubernetes 才初始化 Pod 和运行应用容器。</p><h2 id="init-容器能做什么" tabindex="-1">Init 容器能做什么？ <a class="header-anchor" href="#init-容器能做什么" aria-label="Permalink to &quot;Init 容器能做什么？&quot;">​</a></h2><p>因为 Init 容器具有与应用程序容器分离的单独镜像，所以它们的启动相关代码具有如下优势：</p><ul><li>它们可以包含并运行实用工具，但是出于安全考虑，是不建议在应用程序容器镜像中包含这些实用工具的。</li><li>它们可以包含使用工具和定制化代码来安装，但是不能出现在应用程序镜像中。例如，创建镜像没必要 <code>FROM</code> 另一个镜像，只需要在安装过程中使用类似 <code>sed</code>、 <code>awk</code>、 <code>python</code> 或 <code>dig</code> 这样的工具。</li><li>应用程序镜像可以分离出创建和部署的角色，而没有必要联合它们构建一个单独的镜像。</li><li>Init 容器使用 Linux Namespace，所以相对应用程序容器来说具有不同的文件系统视图。因此，它们能够具有访问 Secret 的权限，而应用程序容器则不能。</li><li>它们必须在应用程序容器启动之前运行完成，而应用程序容器是并行运行的，所以 Init 容器能够提供了一种简单的阻塞或延迟应用容器的启动的方法，直到满足了一组先决条件。</li></ul><h2 id="初始化容器和普通容器及poststart有啥区别" tabindex="-1">初始化容器和普通容器及PostStart有啥区别 <a class="header-anchor" href="#初始化容器和普通容器及poststart有啥区别" aria-label="Permalink to &quot;初始化容器和普通容器及PostStart有啥区别&quot;">​</a></h2><p>初始化容器和PostStart区别如下：</p><ul><li>PostStart:依赖主应用的环境，而且并不一定先于Command运行</li><li>InitContainer：不依赖主应用的环境，可以有更高的权限和更多的工具，一定会在主应用启动之前完成</li></ul><p>初始化容器和普通容器的区别如下：</p><ul><li>初始化容器总是运行到完成</li><li>初始化容器每个都必须在下一个启动之前成功完成</li><li>如果 Pod 的 Init 容器失败，Kubernetes 会不断地 重启该 Pod，直到 Init 容器成功为止，但是Pod 对应的 restartPolicy 值为 Never，Kubernetes 不会重新启动 Pod</li><li>初始化容器不支持 lifecycle、livenessProbe、readinessProbe 和 startupProbe， 因为它们必须在 Pod 就绪之前运行完成</li></ul>',13);function _(t,h,u,P,m,I){return s(),i("div",null,[e("h1",d,[o(r(t.$frontmatter.title)+" ",1),c]),p])}const k=a(l,[["render",_]]);export{f as __pageData,k as default};
